import { NodeSDK } from '@opentelemetry/sdk-node';
import { SimpleSpanProcessor } from '@opentelemetry/sdk-trace-base';
import { OTLPTraceExporter } from '@opentelemetry/exporter-trace-otlp-http';
import { Frontman } from '@frontman-ai/nextjs';

export async function register() {
  // Frontman middleware instance
  const frontmanMiddleware = Frontman({ host: 'test.frontman.dev', matcher: ['/frontman', '/frontman/:path*'] });
  void frontmanMiddleware;

  if (process.env.NEXT_RUNTIME === 'nodejs') {
    const { setup } = await import('@frontman-ai/nextjs/Instrumentation');
    const [logProcessor, spanProcessor] = setup();

    const sdk = new NodeSDK({
      logRecordProcessors: [logProcessor],
      spanProcessors: [spanProcessor, new SimpleSpanProcessor(new OTLPTraceExporter())],
    });
    sdk.start();
  }
}
